import{_ as o,c as n,o as i,ai as a}from"./chunks/framework.TS84ywiI.js";const b=JSON.parse('{"title":"引言：庞大的代码量让人心生怠倦，有趣的故事让技术也疯狂","description":"","frontmatter":{},"headers":[],"relativePath":"Spring/Spring源码故事（瞎编版）/面筋哥IoC容器的一天(上).md","filePath":"Spring/Spring源码故事（瞎编版）/面筋哥IoC容器的一天(上).md"}'),d={name:"Spring/Spring源码故事（瞎编版）/面筋哥IoC容器的一天(上).md"};function t(c,e,r,p,l,s){return i(),n("div",null,e[0]||(e[0]=[a('<h1 id="引言-庞大的代码量让人心生怠倦-有趣的故事让技术也疯狂" tabindex="-1">引言：庞大的代码量让人心生怠倦，有趣的故事让技术也疯狂 <a class="header-anchor" href="#引言-庞大的代码量让人心生怠倦-有趣的故事让技术也疯狂" aria-label="Permalink to &quot;引言：庞大的代码量让人心生怠倦，有趣的故事让技术也疯狂&quot;">​</a></h1><p>大家好，我是 IoC 容器家族的第 17 代传人，我们家族世世代代在 spring 商业街上卖烤面筋，大家都叫我“面筋哥”，另外我爹还给我起了个高大上的英文名字，叫 <code>FileSystemXmlApplicationContext</code>，但有群臭猴子嫌麻烦，就天天叫我的外号，害得我差点忘了自己的本名。不过无所谓咯，只要生意兴隆，这都是小事。</p><p>前几天出摊卖烤面筋时，灵感大作，即兴唱了一首“我的烤面筋”，被网友拍下来传到某站上成了网红，现在我要趁势而上，把自己祖传的烤面筋工艺宣传出去，让我那个臭弟弟 <code>ClassPathXmlApplicationContext</code> 知道，谁才是 IoC 容器的正统传人！</p><h2 id="第一阶段-beandefinition-资源定位-reader-beandefinitionreader-documentreader" tabindex="-1">第一阶段：BeanDefinition 资源定位（Reader，beanDefinitionReader，documentReader） <a class="header-anchor" href="#第一阶段-beandefinition-资源定位-reader-beandefinitionreader-documentreader" aria-label="Permalink to &quot;第一阶段：BeanDefinition 资源定位（Reader，beanDefinitionReader，documentReader）&quot;">​</a></h2><p>新的一天从 <code>new</code> 开始，但我却还躺在床上各种伸懒腰，毕竟我现在也是个小老板了，很多杂七杂八的活雇几个小弟干就行咯。我拿起我的 iBanana11 看了看商业街董事（某程序员）发的“精选优质面筋批发市场地址”，然后深吸一口气 <code>refresh()</code>，闭上眼 <code>obtainFreshBeanFactory()</code>，气沉丹田 <code>refreshBeanFactory()</code>，大喊一声：</p><blockquote><p>loadBeanDefinitions()！</p></blockquote><p>我虎背熊腰的小弟 <code>beanDefinitionReader</code> 破门而入，尖声细语地问道：</p><blockquote><p>老板有何吩咐 ~？</p></blockquote><p>我起身叮嘱了他几件事后，把自己的联系方式（引用）、面筋批发市场的地址（spring 配置文件地址）交给他，就又躺回去盯着天花板上的钻石吊灯继续发呆。</p><p>Reader 家有一对兄妹，哥哥 <code>beanDefinitionReader</code> 虎背熊腰大老粗，却尖声细语；妹妹 <code>documentReader</code> 心灵手巧，可惜比较宅，我们几乎没怎么见过。兄妹俩相互配合把上午的准备工作做了大半。</p><p>不要看我天天躺着，彗星晒屁股了还眯着眼，他们兄妹俩在几点几分打个喷嚏我都能算到，毕竟我基因里都写满了“烤面筋工艺完整详细流程”。</p><p>哥哥现在肯定在开着小面包车拿着我给他的地址（<code>locations</code>）到处找面筋等原材料，然后把找到的面筋打包进 <code>Document</code> 对象，拉回来交给妹妹 <code>documentReader</code> 进行精心处理，连同 <code>Document</code> 给她的还有一个“神秘人”的联系方式。</p><p>妹妹会打开 <code>Document</code> 取出其中最大的几个箱子（<code>&lt;beans&gt;</code>、<code>&lt;import&gt;</code>、<code>&lt;alias&gt;</code> 等一级标签），分别进行处理。其中 <code>beans</code> 箱最为重要，里面放满了夜市的主角，烤面筋的核心材料。</p><h2 id="第二阶段-将-bean-解析封装成-beandefinitionholder-beandefinitionparserdelegate" tabindex="-1">第二阶段：将 bean 解析封装成 BeanDefinitionHolder（BeanDefinitionParserDelegate） <a class="header-anchor" href="#第二阶段-将-bean-解析封装成-beandefinitionholder-beandefinitionparserdelegate" aria-label="Permalink to &quot;第二阶段：将 bean 解析封装成 BeanDefinitionHolder（BeanDefinitionParserDelegate）&quot;">​</a></h2><p>之后妹妹会拿起我们 IoC 家族祖传的面筋处理神器 <code>BeanDefinitionParserDelegate</code>，从 <code>beans</code> 箱里面一个一个取出形态各异的面筋 bean 分别进行加工处理。</p><p>刚拿出来的面筋 bean 是不会直接烤了卖的，我们会将 bean 用神器 <code>ParserDelegate</code> 进行九九八十一道细致处理，所以我们家烤出来的面筋才会如此劲道美味，世世代代延绵不断。</p><p>不过处理程序再怎么细致复杂，也不过就是分为两大部分：</p><ol><li>处理 bean 的属性信息，如 <code>id</code>、<code>class</code>、<code>scope</code> 等；</li><li>处理 bean 的子元素，主要是 <code>&lt;property&gt;</code> 标签，而 <code>&lt;property&gt;</code> 标签又有属性和子元素，且子元素类型更加丰富复杂，可能是 <code>&lt;map&gt;</code>、<code>&lt;set&gt;</code>、<code>&lt;list&gt;</code>、<code>&lt;array&gt;</code> 等。</li></ol><p>所以如果你们想学我家的祖传秘方，开个同样的摊子干倒我，也不是这么容易的哦。</p><p>经过上面的步骤，一个配置文件中的面筋 bean 就被处理包装成了半成品 <code>BeanDefinitionHolder</code>。</p><h2 id="第三阶段-将-beandefinition-注册进-ioc-容器-beandefinitionreaderutils" tabindex="-1">第三阶段：将 BeanDefinition 注册进 IoC 容器（BeanDefinitionReaderUtils） <a class="header-anchor" href="#第三阶段-将-beandefinition-注册进-ioc-容器-beandefinitionreaderutils" aria-label="Permalink to &quot;第三阶段：将 BeanDefinition 注册进 IoC 容器（BeanDefinitionReaderUtils）&quot;">​</a></h2><p>妹妹在用神器 <code>BeanDefinitionParserDelegate</code> 经过一顿疯狂操作之后，将包装好的半成品 <code>BeanDefinitionHolder</code> 扔进传输机 <code>BeanDefinitionReaderUtils</code>，并且输入哥哥给她的神秘人地址，就继续处理下一个面筋 bean 咯。</p><p>之后，传输机将 <code>BeanDefinitionHolder</code> 的包装打开，分别取出 <code>beanName</code>（面筋的唯一标识）和 <code>BeanDefinition</code>（面筋本筋），传输的目的地是 <code>BeanDefinitionRegistry</code> 的工作室（这就是我前面给哥哥 <code>beanDefinitionReader</code> 的地址）。</p><p>这家工作室的 <code>BeanDefinitionRegistry</code> 其实就是我的影分身之一，因为我的祖先实现了这个接口。</p><p>影分身 <code>Registry</code> 检查一下传输过来的 <code>beanName</code>（面筋的唯一标识）和 <code>BeanDefinition</code>（面筋本筋），如果没什么问题，就把它们用根绳子系在一起扔进我的“王之面筋宝库”，一个 <code>ConcurrentHashMap&lt;String, BeanDefinition&gt;(64)</code>，也有人把我的“面筋宝库”称作 “IoC 容器本器”，我也无可辩驳，谁让他们吃面筋付钱了呢。</p><p>就这样，每一种取出来的面筋都会经过这些处理。</p><p>等到所有的面筋处理完了，也差不多到了傍晚，每到这时我就会拿起梳子和发油，对着镶满钻石的镜子，梳理整齐与徐峥同款的明星发型，唱着魔性的：</p><blockquote><p>我的烤面筋 ~</p></blockquote><p>骑着小车车，出摊咯 ~</p><hr><p>面筋等原材料基本上都已经处理完毕，但把这些原材料变成程序员手中的“烤面筋”也是一门复杂而精细的手艺，老铁们记得 <code>watch</code>、<code>star</code>、<code>fork</code>，素质三连一波，下一期我将带领你们走进 spring 商业街的夜市，一起烤出香喷喷的面筋，成为这条 <code>gai</code> 上最亮的仔！</p>',31)]))}const D=o(d,[["render",t]]);export{b as __pageData,D as default};
